var fs = require('fs');
var path = require('path');
var filePath = path.join(__dirname, 'gen-tm.js');

function j(v) { return JSON.stringify(v); }
function cb(lines) { return 'codeBlock([' + lines.map(function(l){return j(l);}).join(',') + '])'; }
function q(q,a) { return 'q('+j(q)+','+j(a)+')'; }
function m(q,opts,a,e) { return 'm('+j(q)+','+j(opts)+','+j(a)+','+j(e)+')'; }
function e(title,uc,code,desc) { return 'e('+j(title)+','+j(uc)+','+code+','+j(desc)+')'; }
function d(h,t) { return 'd('+j(h)+','+j(t)+')'; }

function rect(x,y,w,h,fill,stroke,t1,t2,c1,c2) {
  return 'R('+x+','+y+','+w+','+h+','+j(fill)+','+j(stroke||'')+','+j(t1||'')+','+j(t2||'')+','+j(c1||'')+','+j(c2||'')+')';
}
function arrow(x1,y1,x2,y2,c) {
  return 'A('+x1+','+y1+','+x2+','+y2+','+j(c||'')+')';
}
function text(x,y,txt,size,color,anchor) {
  return 'T('+x+','+y+','+j(txt)+','+j(String(size||''))+','+j(color||'')+','+j(anchor||'')+')';
}
function svg(w,h,title,inner) {
  return 'svgW('+w+','+h+','+j(title)+','+inner+')';
}

function topic(id, title, difficulty, minutes, tldr, layman, deep, intAns, questions, svgParts, examples, mcqs) {
  var tldrJ = tldr.map(function(s){return j(s);});
  var deepJ = deep.map(function(dd){return d(dd[0],dd[1]);});
  var qJ = questions.map(function(qa){return q(qa[0],qa[1]);});
  var eJ = examples.map(function(ex){return e(ex[0],ex[1],cb(ex[2]),ex[3]);});
  var mJ = mcqs.map(function(mc){return m(mc[0],mc[1],mc[2],mc[3]);});
  var svgStr = svgParts.join('+');
  return 'addTopic('+j(id)+','+j(title)+','+j(difficulty)+','+minutes+',['+tldrJ.join(',')+'],'+j(layman)+',['+deepJ.join(',')+'],'+j(intAns)+',['+qJ.join(',')+'],'+svgStr+',['+eJ.join(',')+'],['+mJ.join(',')+'])';
}

